 5 Gibbs sampler 5.1 The main Gibbs sampler The main Gibbs sampler is called run.Gibbs(). #&#39; Sample a prior state trajectory from a Dynamic Linear Model (DLM). #&#39; #&#39; Simulates a state sequence \eqn{	heta_{1:T}} from a Gaussian DLM defined by: #&#39; \deqn{	heta_0 \sim N(m_0, C_0)} #&#39; \deqn{	heta_t = G 	heta_{t-1} + w_t, \quad w_t \sim N(0, W)} #&#39; #&#39; @param TT Number of time steps. #&#39; @param m0 Prior mean vector for the initial state. #&#39; @param C0 Prior covariance matrix for the initial state. #&#39; @param G State transition matrix. #&#39; @param W State evolution covariance matrix. #&#39; #&#39; @return A matrix of size TT x p containing the sampled state trajectory. sample_prior_theta &lt;- function(TT, m0, C0, G, W){ p &lt;- length(m0) theta &lt;- matrix(NA, nrow = TT, ncol = p) ## Sample initial state theta_0 theta0 &lt;- rmvn(m0, C0) prev &lt;- theta0 ## Forward simulation for(tt in seq_len(TT)){ ## Mean of theta_t given theta_{t-1} mu_t &lt;- as.vector(G %*% prev) ## Sample theta_t th &lt;- rmvn(mu_t, W) theta[tt, ] &lt;- th prev &lt;- th } return(theta) } #&#39; Approximate Polya-Gamma sampler. #&#39; #&#39; If BayesLogit is installed, this uses BayesLogit::rpg(). #&#39; Otherwise, it uses a truncated infinite-sum approximation. #&#39; #&#39; @param n Number of samples. #&#39; @param h Shape parameter. #&#39; @param z Location parameter. #&#39; @param trunc Truncation level for approximation. Defaults to 80. rpg &lt;- function(n, h, z, trunc = 80){ h &lt;- rep(h, length.out = n) z &lt;- rep(z, length.out = n) if(requireNamespace(&quot;BayesLogit&quot;, quietly = TRUE)){ return(as.numeric(BayesLogit::rpg(n, h, z))) } out &lt;- numeric(n) m &lt;- seq_len(trunc) for(i in seq_len(n)){ denom &lt;- (m - 0.5)^2 + z[i]^2 / (4 * pi^2) g &lt;- rgamma(trunc, shape = h[i], rate = 1) out[i] &lt;- sum(g / denom) / (2 * pi^2) } return(out) } #&#39; Sample omega_{k,t} once per MCMC sweep. #&#39; #&#39; @param Y Response matrix (n x TT). #&#39; @param Z Cluster allocation vector. #&#39; @param theta State parameters (K x TT x p). #&#39; @param Fmat Design matrix (TT x p). #&#39; @param r_tune Tuning parameter for Polya-Gamma augmentation. #&#39; @param K Number of clusters. sample_omega_all &lt;- function(Y, Z, theta, Fmat, r_tune, K){ TT &lt;- ncol(Y) stats &lt;- cluster_stats(Z, Y, K) N &lt;- stats$N S &lt;- stats$S omega &lt;- matrix(NA_real_, nrow = K, ncol = TT) eta &lt;- get_eta(theta, Fmat) for(k in seq_len(K)){ if(N[k] == 0) next for(tt in seq_len(TT)){ psi_kt &lt;- eta[k, tt] + log(N[k]) - log(r_tune) B_kt &lt;- r_tune + S[k, tt] omega[k, tt] &lt;- max(rpg(1, B_kt, psi_kt), 1e-8) } } ret &lt;- list(omega = omega, stats = stats) return(ret) } #&#39; Forward-filtering backward-sampling for one cluster under the #&#39; Polya-Gamma Gaussian representation. #&#39; #&#39; @param N Cluster size. #&#39; @param S Cluster-specific sufficient statistics. #&#39; @param omega_k Polya-Gamma auxiliary variables for cluster k. #&#39; @param Fmat Design matrix (TT x p). #&#39; @param m0 Prior mean vector. #&#39; @param C0 Prior covariance matrix. #&#39; @param G State transition matrix. #&#39; @param W State evolution covariance. #&#39; @param r_tune Tuning parameter for Polya-Gamma augmentation. ffbs_one_cluster &lt;- function(N, S, omega_k, Fmat, m0, C0, G, W, r_tune){ TT &lt;- length(S) p &lt;- length(m0) ## If the cluster is empty, draw from the prior DLM. if(N == 0){ return(sample_prior_theta(TT, m0, C0, G, W)) } rvec &lt;- rep(r_tune, TT) bar_r &lt;- log(rvec) - log(N) kappa &lt;- 0.5 * (S - rvec) omega_k &lt;- pmax(omega_k, 1e-8) ## Pseudo observation: ## y*_{k,t} = F&#39; theta_{k,t} + epsilon, epsilon ~ N(0, 1 / omega) ystar &lt;- bar_r + kappa / omega_k V &lt;- 1 / omega_k a_pred &lt;- matrix(NA, nrow = TT, ncol = p) m_filt &lt;- matrix(NA, nrow = TT, ncol = p) R_pred &lt;- array(NA, dim = c(p, p, TT)) C_filt &lt;- array(NA, dim = c(p, p, TT)) m_prev &lt;- m0 C_prev &lt;- C0 ## Forward filtering for(tt in seq_len(TT)){ Ft &lt;- matrix(Fmat[tt, ], ncol = 1) a &lt;- as.vector(G %*% m_prev) R &lt;- G %*% C_prev %*% t(G) + W R &lt;- (R + t(R)) / 2 f &lt;- as.numeric(t(Ft) %*% a) Q &lt;- as.numeric(t(Ft) %*% R %*% Ft + V[tt]) K_gain &lt;- as.vector(R %*% Ft) / Q m &lt;- a + K_gain * (ystar[tt] - f) C &lt;- R - (R %*% Ft %*% t(Ft) %*% R) / Q C &lt;- (C + t(C)) / 2 a_pred[tt, ] &lt;- a R_pred[, , tt] &lt;- R m_filt[tt, ] &lt;- m C_filt[, , tt] &lt;- C m_prev &lt;- m C_prev &lt;- C } ## Backward sampling theta &lt;- matrix(NA, nrow = TT, ncol = p) theta[TT, ] &lt;- rmvn(m_filt[TT, ], C_filt[, , TT]) if(TT &gt; 1){ for(tt in seq(TT - 1, 1)){ B_smooth &lt;- C_filt[, , tt] %*% t(G) %*% solve(R_pred[, , tt + 1]) h &lt;- m_filt[tt, ] + B_smooth %*% (theta[tt + 1, ] - a_pred[tt + 1, ]) H &lt;- C_filt[, , tt] - B_smooth %*% R_pred[, , tt + 1] %*% t(B_smooth) H &lt;- (H + t(H)) / 2 theta[tt, ] &lt;- rmvn(as.vector(h), H) } } return(theta) } #&#39; Sample all state trajectories using FFBS. #&#39; #&#39; @param Y Response matrix (n x TT). #&#39; @param Z Cluster allocation vector. #&#39; @param theta Current state parameters (K x TT x p). #&#39; @param Fmat Design matrix (TT x p). #&#39; @param m0 Prior mean vector. #&#39; @param C0 Prior covariance matrix. #&#39; @param G State transition matrix. #&#39; @param W State evolution covariance. #&#39; @param r_tune Tuning parameter for Polya-Gamma augmentation. #&#39; @param K Number of clusters. sample_theta_all &lt;- function(Y, Z, theta, Fmat, m0, C0, G, W, r_tune, K){ out &lt;- sample_omega_all(Y, Z, theta, Fmat, r_tune, K) omega &lt;- out$omega N &lt;- out$stats$N S &lt;- out$stats$S TT &lt;- ncol(Y) p &lt;- length(m0) theta_new &lt;- array(NA, dim = c(K, TT, p)) for(k in seq_len(K)){ theta_new[k, , ] &lt;- ffbs_one_cluster( N = N[k], S = S[k, ], omega_k = omega[k, ], Fmat = Fmat, m0 = m0, C0 = C0, G = G, W = W, r_tune = r_tune ) } return(theta_new) } #&#39; Sample cluster allocations Z_i conditional on theta. #&#39; #&#39; @param Y Response matrix (n x TT). #&#39; @param theta State parameters (K x TT x p). #&#39; @param Fmat Design matrix (TT x p). #&#39; @param pi_vec Cluster probability vector. update_Z_given_theta &lt;- function(Y, theta, Fmat, pi_vec){ n &lt;- nrow(Y) TT &lt;- ncol(Y) K &lt;- dim(theta)[1] eta &lt;- get_eta(theta, Fmat) lambda &lt;- exp(eta) Z_new &lt;- integer(n) for(i in seq_len(n)){ logp &lt;- numeric(K) for(k in seq_len(K)){ logp[k] &lt;- log(pi_vec[k] + 1e-16) + sum(Y[i, ] * eta[k, ] - lambda[k, ]) } prob &lt;- exp(logp - logsumexp(logp)) Z_new[i] &lt;- sample(seq_len(K), size = 1, prob = prob) } return(Z_new) } #&#39; Label-switching correction via ordering by average fitted intensity. #&#39; #&#39; Simple identifiability constraint: order clusters by average #&#39; fitted intensity. This is suitable when true clusters are generated #&#39; with increasing average intensity. #&#39; #&#39; @param theta State parameters (K x TT x p). #&#39; @param pi_vec Cluster probability vector. #&#39; @param Z Cluster allocation vector. #&#39; @param Fmat Design matrix (TT x p). relabel_by_mean_intensity &lt;- function(theta, pi_vec, Z, Fmat){ K &lt;- dim(theta)[1] lambda &lt;- get_lambda(theta, Fmat) mean_lambda &lt;- rowMeans(lambda) old_order &lt;- order(mean_lambda) theta_new &lt;- theta[old_order, , , drop = FALSE] pi_new &lt;- pi_vec[old_order] old_to_new &lt;- integer(K) old_to_new[old_order] &lt;- seq_len(K) Z_new &lt;- old_to_new[Z] ret &lt;- list( theta = theta_new, pi = pi_new, Z = Z_new, order = old_order ) return(ret) } #&#39; Run the full Gibbs sampler for Bayesian dynamic network clustering. #&#39; #&#39; This function runs the complete MCMC algorithm for fitting Bayesian #&#39; dynamic network models with Polya-Gamma augmentation and forward-filtering #&#39; backward-sampling (FFBS). #&#39; #&#39; @param Y Response matrix (n x TT) of count data. #&#39; @param Fmat Design matrix (TT x p) for the state-space model. #&#39; @param K Number of clusters. #&#39; @param n_iter Total number of MCMC iterations. #&#39; @param burn Number of burn-in iterations to discard. #&#39; @param alpha_pi Dirichlet prior concentration for cluster probabilities. #&#39; Can be a scalar (recycled) or vector of length K. Defaults to rep(1, K). #&#39; @param m0 Prior mean vector for initial state (length p). #&#39; @param C0 Prior covariance matrix for initial state (p x p). #&#39; @param G State transition matrix (p x p). #&#39; @param W State evolution covariance matrix (p x p). #&#39; @param r_tune Tuning parameter for Polya-Gamma augmentation. #&#39; If NULL, automatically computed from Y. #&#39; @param Z_true Optional true cluster labels for diagnostics. #&#39; @param relabel_freq Frequency of label-switching correction. #&#39; Defaults to 1 (every iteration). #&#39; @param print_freq Frequency of progress printing. Defaults to 100. #&#39; @param store_theta Whether to store full theta samples. Defaults to FALSE. #&#39; @param seed Optional random seed for reproducibility. #&#39; #&#39; @return A list containing: #&#39; \item{theta}{Posterior samples of state parameters (if store_theta = TRUE).} #&#39; \item{pi}{Posterior samples of cluster probabilities.} #&#39; \item{Z}{Posterior samples of cluster allocations.} #&#39; \item{lambda}{Posterior samples of fitted intensities.} #&#39; \item{mean_lambda}{Posterior samples of mean intensities per cluster.} #&#39; \item{size}{Posterior samples of cluster sizes.} #&#39; \item{ari}{Adjusted Rand Index at each iteration (if Z_true provided).} #&#39; \item{acc}{Best label accuracy at each iteration (if Z_true provided).} #&#39; \item{accept_rate}{Acceptance rate diagnostics.} #&#39; \item{settings}{List of MCMC settings used.} #&#39; #&#39; @export gibbs_sampler &lt;- function(Y, Fmat, K, n_iter = 600, burn = 300, alpha_pi = NULL, m0 = NULL, C0 = NULL, G = NULL, W = NULL, r_tune = NULL, Z_true = NULL, relabel_freq = 1, print_freq = 100, store_theta = FALSE, seed = NULL){ ## Set seed for reproducibility if(!is.null(seed)){ set.seed(seed) } ## Extract dimensions n &lt;- nrow(Y) TT &lt;- ncol(Y) p &lt;- ncol(Fmat) ## Set default MCMC settings if not provided if(is.null(alpha_pi)){ alpha_pi &lt;- rep(1, K) } if(is.null(m0)){ m0 &lt;- c(log(mean(Y) + 0.1), 0) if(length(m0) &lt; p){ m0 &lt;- c(m0, rep(0, p - length(m0))) } } if(is.null(C0)){ C0 &lt;- diag(c(5, 2)) if(nrow(C0) &lt; p){ C0 &lt;- diag(p) * 5 } } if(is.null(G)){ G &lt;- diag(p) } if(is.null(W)){ W &lt;- diag(c(0.02, 0.005)) if(nrow(W) &lt; p){ W &lt;- diag(p) * 0.01 } } if(is.null(r_tune)){ r_tune &lt;- (max(Y) + sqrt(max(Y)) * 3) * 50 } ## Initialize chain Z &lt;- sample(seq_len(K), size = n, replace = TRUE) pi_vec &lt;- rdirichlet1(alpha_pi + tabulate(Z, nbins = K)) theta &lt;- array(NA, dim = c(K, TT, p)) for(k in seq_len(K)){ theta[k, , ] &lt;- sample_prior_theta(TT, m0, C0, G, W) } ## Initial label correction rel &lt;- relabel_by_mean_intensity(theta, pi_vec, Z, Fmat) theta &lt;- rel$theta pi_vec &lt;- rel$pi Z &lt;- rel$Z ## Storage pi_store &lt;- matrix(NA, nrow = n_iter, ncol = K) size_store &lt;- matrix(NA, nrow = n_iter, ncol = K) mean_lambda_store &lt;- matrix(NA, nrow = n_iter, ncol = K) lambda_store &lt;- array(NA, dim = c(n_iter, K, TT)) Z_store &lt;- matrix(NA_integer_, nrow = n_iter, ncol = n) theta_store &lt;- NULL if(store_theta){ theta_store &lt;- array(NA, dim = c(n_iter, K, TT, p)) } ari_store &lt;- numeric(n_iter) acc_store &lt;- numeric(n_iter) start_time &lt;- Sys.time() ## Run MCMC for(iter in seq_len(n_iter)){ ## 1. Sample theta_{k,1:T} using PG + FFBS theta &lt;- sample_theta_all( Y = Y, Z = Z, theta = theta, Fmat = Fmat, m0 = m0, C0 = C0, G = G, W = W, r_tune = r_tune, K = K ) ## 2. Sample allocations Z_i conditional on theta Z &lt;- update_Z_given_theta(Y, theta, Fmat, pi_vec) ## 3. Sample pi (cluster probabilities) Nk &lt;- tabulate(Z, nbins = K) pi_vec &lt;- rdirichlet1(alpha_pi + Nk) ## 4. Label-switching correction ## This imposes the ordering: ## cluster 1 has smallest average intensity, ## cluster K has largest average intensity. if(iter %% relabel_freq == 0){ rel &lt;- relabel_by_mean_intensity(theta, pi_vec, Z, Fmat) theta &lt;- rel$theta pi_vec &lt;- rel$pi Z &lt;- rel$Z } ## Store samples lambda_cur &lt;- get_lambda(theta, Fmat) pi_store[iter, ] &lt;- pi_vec size_store[iter, ] &lt;- tabulate(Z, nbins = K) mean_lambda_store[iter, ] &lt;- rowMeans(lambda_cur) lambda_store[iter, , ] &lt;- lambda_cur Z_store[iter, ] &lt;- Z if(store_theta){ theta_store[iter, , , ] &lt;- theta } ## Diagnostics (if true labels provided) if(!is.null(Z_true)){ ari_store[iter] &lt;- adj_rand_index(Z_true, Z) acc_store[iter] &lt;- best_label_accuracy(Z_true, Z, K) } ## Print progress if(iter %% print_freq == 0){ printprogress( isim = iter, nsim = n_iter, type = &quot;MCMC iteration&quot;, start.time = start_time, fill = TRUE ) if(!is.null(Z_true)){ cat( &quot; | ARI =&quot;, round(ari_store[iter], 3), &quot;| best accuracy =&quot;, round(acc_store[iter], 3), &quot;
&quot; ) } else { cat(&quot;
&quot;) } } } ## Compute effective sample size (optional diagnostic) end_time &lt;- Sys.time() total_time &lt;- as.numeric(difftime(end_time, start_time, units = &quot;secs&quot;)) ## Prepare output ret &lt;- list( theta = theta_store, pi = pi_store, Z = Z_store, lambda = lambda_store, mean_lambda = mean_lambda_store, size = size_store, ari = ari_store, acc = acc_store, settings = list( n_iter = n_iter, burn = burn, K = K, n = n, TT = TT, p = p, alpha_pi = alpha_pi, m0 = m0, C0 = C0, G = G, W = W, r_tune = r_tune, total_time = total_time, seed = seed ) ) class(ret) &lt;- &quot;bdynets_mcmc&quot; return(ret) } #&#39; Summarize MCMC results from gibbs_sampler. #&#39; #&#39; @param object Object of class &quot;bdynets_mcmc&quot;. #&#39; @param burn Number of burn-in iterations to discard. #&#39; @param ... Additional arguments (not used). #&#39; #&#39; @export summary.bdynets_mcmc &lt;- function(object, burn = NULL, ...){ if(is.null(burn)){ burn &lt;- object$settings$burn } n_iter &lt;- object$settings$n_iter keep_idx &lt;- seq(burn + 1, n_iter) cat(&quot;Bayesian Dynamic Network MCMC Summary
&quot;) cat(&quot;=====================================

&quot;) cat(&quot;MCMC Settings:
&quot;) cat(&quot; Total iterations:&quot;, n_iter, &quot;
