&quot;) lambda_mean &lt;- colMeans(object$mean_lambda[keep_idx, , drop = FALSE]) print(round(lambda_mean, 4)) invisible(object) } #&#39; Plot MCMC diagnostics for bdynets_mcmc object. #&#39; #&#39; @param x Object of class &quot;bdynets_mcmc&quot;. #&#39; @param burn Number of burn-in iterations to discard. #&#39; @param type Type of plot: &quot;trace&quot;, &quot;density&quot;, &quot;ari&quot;, or &quot;all&quot;. #&#39; @param ... Additional arguments passed to plot. #&#39; #&#39; @export plot.bdynets_mcmc &lt;- function(x, burn = NULL, type = &quot;all&quot;, ...){ if(is.null(burn)){ burn &lt;- x$settings$burn } keep_idx &lt;- seq(burn + 1, x$settings$n_iter) K &lt;- x$settings$K if(type == &quot;trace&quot; || type == &quot;all&quot;){ ## Trace plots for cluster probabilities matplot( keep_idx, x$pi[keep_idx, ], type = &quot;l&quot;, lty = 1, col = seq_len(K), xlab = &quot;Iteration&quot;, ylab = &quot;Cluster Probability&quot;, main = &quot;Trace Plot: Cluster Probabilities (pi)&quot; ) legend(&quot;topright&quot;, legend = paste(&quot;Cluster&quot;, seq_len(K)), col = seq_len(K), lty = 1, cex = 0.8) } if(type == &quot;ari&quot; || type == &quot;all&quot;){ if(length(x$ari) &gt; 0 &amp;&amp; any(x$ari &gt; 0)){ ## ARI over iterations plot( keep_idx, x$ari[keep_idx], type = &quot;l&quot;, col = &quot;blue&quot;, lwd = 2, xlab = &quot;Iteration&quot;, ylab = &quot;Adjusted Rand Index&quot;, main = &quot;Clustering Accuracy (ARI) Over Iterations&quot; ) abline(h = mean(x$ari[keep_idx]), col = &quot;red&quot;, lty = 2) } } if(type == &quot;size&quot; || type == &quot;all&quot;){ ## Cluster sizes over iterations matplot( keep_idx, x$size[keep_idx, ], type = &quot;l&quot;, lty = 1, col = seq_len(K), xlab = &quot;Iteration&quot;, ylab = &quot;Cluster Size&quot;, main = &quot;Trace Plot: Cluster Sizes&quot; ) legend(&quot;topright&quot;, legend = paste(&quot;Cluster&quot;, seq_len(K)), col = seq_len(K), lty = 1, cex = 0.8) } invisible(x) }

 6 Simulation Study: Bayesian Dynamic Network for Traffic Data This vignette demonstrates a complete simulation study using bdynets on synthetic traffic data from a grid road network. 6.1 1. Synthetic Data Generation 6.1.1 1.1 Create 5×5 Grid Road Network generate_grid_network &lt;- function(rows = 5, cols = 5) { n_nodes &lt;- rows * cols ## Create node coordinates nodes &lt;- expand.grid(row = 1:rows, col = 1:cols) nodes$node_id &lt;- 1:n_nodes ## Create directed edges (each node connects to adjacent nodes) edges &lt;- data.frame( from = integer(), to = integer(), direction = character() ) for (i in 1:rows) { for (j in 1:cols) { node_id &lt;- (i - 1) * cols + j ## Right neighbor if (j &lt; cols) { edges &lt;- rbind(edges, data.frame( from = node_id, to = node_id + 1, direction = &quot;horizontal&quot; )) edges &lt;- rbind(edges, data.frame( from = node_id + 1, to = node_id, direction = &quot;horizontal&quot; )) } ## Down neighbor if (i &lt; rows) { edges &lt;- rbind(edges, data.frame( from = node_id, to = node_id + cols, direction = &quot;vertical&quot; )) edges &lt;- rbind(edges, data.frame( from = node_id + cols, to = node_id, direction = &quot;vertical&quot; )) } } } list( nodes = nodes, edges = edges, n_nodes = n_nodes, n_edges = nrow(edges) ) } network &lt;- generate_grid_network(5, 5) cat(&quot;Network:&quot;, network$n_nodes, &quot;nodes,&quot;, network$n_edges, &quot;edges
&quot;) ## Network: 25 nodes, 80 edges 6.1.2 1.2 Create Time Structure (4 weeks, 48 intervals/day) ## Time parameters intervals_per_day &lt;- 48 # 30-minute intervals n_days &lt;- 28 # 4 weeks TT &lt;- intervals_per_day * n_days # Total time steps ## Create time index time_index &lt;- data.frame( t = 1:TT, day = rep(1:n_days, each = intervals_per_day), interval = rep(1:intervals_per_day, n_days), hour = rep(0:23, each = 2, times = n_days), day_of_week = rep(1:7, each = intervals_per_day, times = 4) ) ## Add peak hour indicators time_index$is_morning_peak &lt;- time_index$hour %in% c(7, 8, 9) time_index$is_evening_peak &lt;- time_index$hour %in% c(17, 18, 19) time_index$is_weekend &lt;- time_index$day_of_week %in% c(6, 7) 6.1.3 1.3 Generate True Cluster Structure ## True number of clusters K_true &lt;- 3 ## Define cluster characteristics (traffic patterns) ## Cluster 1: Low traffic (residential areas) ## Cluster 2: Medium traffic (suburban connectors) ## Cluster 3: High traffic (major arteries/downtown) cluster_profiles &lt;- list( ## Cluster 1: Low, flat pattern list( base = 2, morning_peak = 1.5, evening_peak = 1.3, weekend_effect = 0.7 ), ## Cluster 2: Medium, bimodal pattern list( base = 5, morning_peak = 2.5, evening_peak = 2.0, weekend_effect = 0.6 ), ## Cluster 3: High, strong peaks list( base = 10, morning_peak = 3.5, evening_peak = 3.0, weekend_effect = 0.5 ) ) ## Assign edges to clusters (with some spatial structure) set.seed(20260509) edge_cluster &lt;- rep(1:K_true, length.out = network$n_edges) ## Add some spatial correlation edge_cluster &lt;- sample(edge_cluster, replace = FALSE) ## Create design matrix Fmat (TT x p) p &lt;- 4 # Intercept, morning peak, evening peak, weekend Fmat &lt;- model.matrix( ~ is_morning_peak + is_evening_peak + is_weekend, data = time_index ) colnames(Fmat) &lt;- c(&quot;intercept&quot;, &quot;morning_peak&quot;, &quot;evening_peak&quot;, &quot;weekend&quot;) 6.1.4 1.4 Generate True Parameters ## True theta parameters (K x TT x p) theta_true &lt;- array(0, dim = c(K_true, TT, p)) for (k in 1:K_true) { profile &lt;- cluster_profiles[[k]] ## Base intercept theta_true[k, , 1] &lt;- log(profile$base) ## Peak effects theta_true[k, , 2] &lt;- log(profile$morning_peak) theta_true[k, , 3] &lt;- log(profile$evening_peak) theta_true[k, , 4] &lt;- log(profile$weekend_effect) } ## Add small time-varying component (smooth variation) for (k in 1:K_true) { time_trend &lt;- 0.1 * sin(2 * pi * (1:TT) / intervals_per_day) theta_true[k, , 1] &lt;- theta_true[k, , 1] + time_trend } ## True cluster probabilities pi_true &lt;- c(0.4, 0.35, 0.25) ## Assign edges to clusters Z_true &lt;- edge_cluster 6.1.5 1.5 Simulate Count Data ## Compute intensity for each edge at each time point lambda_matrix &lt;- matrix(0, nrow = network$n_edges, ncol = TT) for (e in 1:network$n_edges) { k &lt;- Z_true[e] eta_e &lt;- rowSums(Fmat * theta_true[k, , ]) lambda_matrix[e, ] &lt;- exp(eta_e) } ## Simulate Poisson counts Y &lt;- matrix(0, nrow = network$n_edges, ncol = TT) for (e in 1:network$n_edges) { Y[e, ] &lt;- rpois(TT, lambda_matrix[e, ]) } cat(&quot;Data dimensions:&quot;, nrow(Y), &quot;edges ×&quot;, ncol(Y), &quot;time points
&quot;) ## Data dimensions: 80 edges × 1344 time points cat(&quot;Total observations:&quot;, length(Y), &quot;
&quot;) ## Total observations: 107520 cat(&quot;Mean count:&quot;, round(mean(Y), 2), &quot;
&quot;) ## Mean count: 7 cat(&quot;Max count:&quot;, max(Y), &quot;
&quot;) ## Max count: 58 6.2 2. Data Visualization 6.2.1 2.1 Network Structure plot_network_structure &lt;- function(network, Z_true) { nodes &lt;- network$nodes edges &lt;- network$edges edges$cluster &lt;- Z_true ## Node positions node_positions &lt;- nodes %&gt;% mutate( x = col, y = -row ## Flip y for plotting ) ## Edge data with cluster colors edge_data &lt;- edges %&gt;% left_join(node_positions, by = c(&quot;from&quot; = &quot;node_id&quot;)) %&gt;% rename(x1 = x, y1 = y) %&gt;% left_join(node_positions, by = c(&quot;to&quot; = &quot;node_id&quot;)) %&gt;% rename(x2 = x, y2 = y) cluster_colors &lt;- brewer.pal(max(Z_true), &quot;Set2&quot;) ggplot() + geom_segment( data = edge_data, aes(x = x1, y = y1, xend = x2, yend = y2, color = factor(cluster)), linewidth = 1.2, arrow = arrow(length = unit(0.15, &quot;cm&quot;), type = &quot;closed&quot;) ) + geom_point( data = node_positions, aes(x = x, y = y), size = 4, color = &quot;darkgray&quot;, shape = 21, fill = &quot;white&quot; ) + geom_text( data = node_positions, aes(x = x, y = y, label = node_id), size = 3, color = &quot;black&quot; ) + scale_color_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:max(Z_true)) ) + coord_fixed() + theme_minimal() + theme( axis.title = element_blank(), axis.text = element_blank(), axis.ticks = element_blank(), panel.grid = element_blank(), legend.position = &quot;bottom&quot; ) + labs(title = &quot;5×5 Grid Road Network with True Cluster Assignments&quot;) } p_network &lt;- plot_network_structure(network, Z_true) p_network 6.2.2 2.2 Time Series of Traffic Counts plot_traffic_timeseries &lt;- function(Y, time_index, Z_true, K) { ## Convert to long format Y_long &lt;- as.data.frame(Y) %&gt;% mutate(edge = 1:nrow(Y)) %&gt;% pivot_longer( cols = -edge, names_to = &quot;time&quot;, values_to = &quot;count&quot; ) %&gt;% mutate( time = as.numeric(gsub(&quot;V&quot;, &quot;&quot;, time)), cluster = Z_true[edge] ) %&gt;% left_join(time_index, by = c(&quot;time&quot; = &quot;t&quot;)) ## Aggregate by cluster and time cluster_summary &lt;- Y_long %&gt;% group_by(cluster, time) %&gt;% summarize( mean_count = mean(count), sd_count = sd(count), .groups = &quot;drop&quot; ) cluster_colors &lt;- brewer.pal(K, &quot;Set2&quot;) ggplot(cluster_summary, aes(x = time, y = mean_count, color = factor(cluster))) + geom_line(linewidth = 1) + geom_ribbon( aes(ymin = mean_count - sd_count, ymax = mean_count + sd_count, fill = factor(cluster)), alpha = 0.2, color = NA ) + scale_color_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:K) ) + scale_fill_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:K), guide = &quot;none&quot; ) + geom_vline( xintercept = seq(1, TT, by = intervals_per_day), linetype = &quot;dashed&quot;, alpha = 0.3 ) + labs( title = &quot;Traffic Count Time Series by Cluster&quot;, subtitle = &quot;Mean ± SD across edges in each cluster&quot;, x = &quot;Time Step (30-min intervals)&quot;, y = &quot;Mean Count&quot; ) + theme_minimal() + theme( legend.position = &quot;bottom&quot;, panel.grid.minor = element_blank() ) } p_timeseries &lt;- plot_traffic_timeseries(Y, time_index, Z_true, K_true) p_timeseries 6.2.3 2.3 Daily Pattern Heatmap plot_daily_pattern &lt;- function(Y, time_index, Z_true, K) { Y_long &lt;- as.data.frame(Y) %&gt;% mutate(edge = 1:nrow(Y)) %&gt;% pivot_longer( cols = -edge, names_to = &quot;time&quot;, values_to = &quot;count&quot; ) %&gt;% mutate( time = as.numeric(gsub(&quot;V&quot;, &quot;&quot;, time)), cluster = Z_true[edge] ) %&gt;% left_join(time_index, by = c(&quot;time&quot; = &quot;t&quot;)) ## Aggregate by cluster, hour, and day type pattern_summary &lt;- Y_long %&gt;% group_by(cluster, hour, is_weekend) %&gt;% summarize( mean_count = mean(count), .groups = &quot;drop&quot; ) %&gt;% mutate( day_type = ifelse(is_weekend, &quot;Weekend&quot;, &quot;Weekday&quot;) ) ggplot(pattern_summary, aes(x = hour, y = factor(cluster), fill = mean_count)) + geom_tile(color = &quot;white&quot;, linewidth = 0.5) + geom_text( aes(label = round(mean_count, 1)), size = 3, color = &quot;black&quot; ) + facet_wrap(~ day_type, ncol = 2) + scale_fill_gradientn( name = &quot;Mean Count&quot;, colors = brewer.pal(9, &quot;YlOrRd&quot;), na.value = &quot;white&quot; ) + scale_y_discrete(labels = function(x) paste(&quot;Cluster&quot;, x)) + labs( title = &quot;Daily Traffic Patterns by Cluster&quot;, subtitle = &quot;Average count by hour and day type&quot;, x = &quot;Hour of Day&quot;, y = &quot;Cluster&quot; ) + theme_minimal() + theme( legend.position = &quot;right&quot;, panel.grid = element_blank(), axis.text.y = element_text(size = 10) ) } p_heatmap &lt;- plot_daily_pattern(Y, time_index, Z_true, K_true) p_heatmap 6.3 3. Run MCMC ## MCMC settings n_iter &lt;- 800 burn &lt;- 400 K_fit &lt;- K_true ## Prior settings alpha_pi &lt;- rep(1, K_fit) m0_fit &lt;- c(log(mean(Y) + 0.1), 0, 0, 0) C0_fit &lt;- diag(4) * 5 G_fit &lt;- diag(4) W_fit &lt;- diag(4) * 0.01 r_tune &lt;- (max(Y) + sqrt(max(Y)) * 3) * 50 cat(&quot;Running MCMC with&quot;, n_iter, &quot;iterations...
&quot;) ## Run Gibbs sampler mcmc_result &lt;- bdynets::gibbs_sampler( Y = Y, Fmat = Fmat, K = K_fit, n_iter = n_iter, burn = burn, alpha_pi = alpha_pi, m0 = m0_fit, C0 = C0_fit, G = G_fit, W = W_fit, r_tune = r_tune, Z_true = Z_true, relabel_freq = 1, print_freq = 100, store_theta = TRUE, seed = 20260509 ) cat(&quot;MCMC completed in&quot;, round(mcmc_result$settings$total_time, 2), &quot;seconds
&quot;) 6.4 4. MCMC Diagnostics 6.4.1 4.1 Trace Plots plot_trace_diagnostics &lt;- function(mcmc_result) { burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) K &lt;- mcmc_result$settings$K ## Cluster probabilities pi_long &lt;- as.data.frame(mcmc_result$pi[keep_idx, ]) %&gt;% mutate(iteration = keep_idx) %&gt;% pivot_longer( cols = -iteration, names_to = &quot;cluster&quot;, values_to = &quot;value&quot; ) %&gt;% mutate(cluster = gsub(&quot;V&quot;, &quot;&quot;, cluster)) cluster_colors &lt;- brewer.pal(K, &quot;Set2&quot;) p_pi &lt;- ggplot(pi_long, aes(x = iteration, y = value, color = cluster)) + geom_line(alpha = 0.7, linewidth = 0.8) + scale_color_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:K) ) + labs( title = &quot;Trace Plot: Cluster Probabilities (π)&quot;, x = &quot;Iteration&quot;, y = &quot;Probability&quot; ) + theme_minimal() + theme( legend.position = &quot;bottom&quot;, panel.grid.minor = element_blank() ) ## Cluster sizes size_long &lt;- as.data.frame(mcmc_result$size[keep_idx, ]) %&gt;% mutate(iteration = keep_idx) %&gt;% pivot_longer( cols = -iteration, names_to = &quot;cluster&quot;, values_to = &quot;value&quot; ) %&gt;% mutate(cluster = gsub(&quot;V&quot;, &quot;&quot;, cluster)) p_size &lt;- ggplot(size_long, aes(x = iteration, y = value, color = cluster)) + geom_line(alpha = 0.7, linewidth = 0.8) + scale_color_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:K), guide = &quot;none&quot; ) + labs( title = &quot;Trace Plot: Cluster Sizes&quot;, x = &quot;Iteration&quot;, y = &quot;Number of Edges&quot; ) + theme_minimal() + theme( legend.position = &quot;none&quot;, panel.grid.minor = element_blank() ) p_pi / p_size + plot_layout(heights = c(1, 1)) } p_trace &lt;- plot_trace_diagnostics(mcmc_result) p_trace 6.4.2 4.2 Convergence Diagnostics (ARI &amp; Accuracy) plot_convergence_diagnostics &lt;- function(mcmc_result) { burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) diagnostics &lt;- data.frame( iteration = keep_idx, ARI = mcmc_result$ari[keep_idx], Accuracy = mcmc_result$acc[keep_idx] ) %&gt;% pivot_longer( cols = c(ARI, Accuracy), names_to = &quot;metric&quot;, values_to = &quot;value&quot; ) ggplot(diagnostics, aes(x = iteration, y = value, color = metric)) + geom_line(linewidth = 1.2) + geom_hline( data = diagnostics %&gt;% group_by(metric) %&gt;% summarize(mean_val = mean(value)), aes(yintercept = mean_val, color = metric), linetype = &quot;dashed&quot;, linewidth = 1 ) + scale_color_manual( name = &quot;Metric&quot;, values = c(&quot;ARI&quot; = &quot;#2C7BB6&quot;, &quot;Accuracy&quot; = &quot;#D7191C&quot;), labels = c(&quot;ARI&quot; = &quot;Adjusted Rand Index&quot;, &quot;Accuracy&quot; = &quot;Best Label Accuracy&quot;) ) + labs( title = &quot;MCMC Convergence: Clustering Accuracy&quot;, subtitle = paste(&quot;Post burn-in mean ARI:&quot;, round(mean(mcmc_result$ari[keep_idx]), 3), &quot;| Mean Accuracy:&quot;, round(mean(mcmc_result$acc[keep_idx]), 3)), x = &quot;Iteration&quot;, y = &quot;Value&quot; ) + theme_minimal() + theme( legend.position = &quot;bottom&quot;, panel.grid.minor = element_blank() ) } p_convergence &lt;- plot_convergence_diagnostics(mcmc_result) p_convergence 6.4.3 4.3 Posterior Distributions plot_posterior_distributions &lt;- function(mcmc_result) { burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) K &lt;- mcmc_result$settings$K ## Posterior of cluster probabilities pi_long &lt;- as.data.frame(mcmc_result$pi[keep_idx, ]) %&gt;% pivot_longer( cols = everything(), names_to = &quot;cluster&quot;, values_to = &quot;value&quot; ) %&gt;% mutate(cluster = gsub(&quot;V&quot;, &quot;&quot;, cluster)) cluster_colors &lt;- brewer.pal(K, &quot;Set2&quot;) ggplot(pi_long, aes(x = value, fill = cluster)) + geom_density(alpha = 0.6, adjust = 1.2) + scale_fill_manual( name = &quot;Cluster&quot;, values = cluster_colors, labels = paste(&quot;Cluster&quot;, 1:K) ) + labs( title = &quot;Posterior Distributions: Cluster Probabilities&quot;, x = &quot;Probability&quot;, y = &quot;Density&quot; ) + theme_minimal() + theme( legend.position = &quot;bottom&quot;, panel.grid.minor = element_blank() ) } p_posterior &lt;- plot_posterior_distributions(mcmc_result) p_posterior 6.5 5. Estimation Accuracy 6.5.1 5.1 Cluster Recovery plot_cluster_recovery &lt;- function(mcmc_result, Z_true, K) { burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) ## Get posterior mode of Z for each edge Z_post &lt;- mcmc_result$Z[keep_idx, ] Z_hat &lt;- apply(Z_post, 2, function(x) { which.max(tabulate(x, nbins = K)) }) ## Confusion matrix conf_matrix &lt;- table(True = Z_true, Estimated = Z_hat) conf_long &lt;- as.data.frame(conf_matrix) %&gt;% filter(Freq &gt; 0) cluster_colors &lt;- brewer.pal(K, &quot;Set2&quot;) ggplot(conf_long, aes(x = Estimated, y = True, fill = Freq)) + geom_tile(color = &quot;white&quot;, linewidth = 1) + geom_text( aes(label = Freq), size = 6, color = &quot;black&quot; ) + scale_fill_gradientn( name = &quot;Count&quot;, colors = brewer.pal(9, &quot;Blues&quot;), na.value = &quot;white&quot; ) + scale_x_discrete( name = &quot;Estimated Cluster&quot;, labels = paste(&quot;Cluster&quot;, 1:K) ) + scale_y_discrete( name = &quot;True Cluster&quot;, labels = paste(&quot;Cluster&quot;, 1:K) ) + labs( title = &quot;Cluster Recovery: Confusion Matrix&quot;, subtitle = paste(&quot;ARI =&quot;, round(adj_rand_index(Z_true, Z_hat), 3)), x = &quot;Estimated Cluster&quot;, y = &quot;True Cluster&quot; ) + coord_fixed() + theme_minimal() + theme( panel.grid = element_blank(), axis.text = element_text(size = 11) ) } p_recovery &lt;- plot_cluster_recovery(mcmc_result, Z_true, K_true) p_recovery 6.5.2 5.2 Intensity Estimation plot_intensity_estimation &lt;- function(mcmc_result, Y, Fmat, Z_true, K, theta_true = NULL) { burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) ## Posterior mean lambda (dimensions: K × TT) lambda_mean &lt;- apply(mcmc_result$lambda[keep_idx, , ], c(2, 3), mean) ## True lambda (compute from theta_true) TT &lt;- ncol(Y) n_edges &lt;- nrow(Y) lambda_true &lt;- matrix(0, nrow = n_edges, ncol = TT) lambda_est &lt;- matrix(0, nrow = n_edges, ncol = TT) if (!is.null(theta_true)) { ## Compute true lambda for each edge for (e in 1:n_edges) { k &lt;- Z_true[e] eta_e &lt;- rowSums(Fmat * theta_true[k, , ]) lambda_true[e, ] &lt;- exp(eta_e) ## Estimated lambda uses the cluster&#39;s posterior mean lambda_est[e, ] &lt;- lambda_mean[k, ] } } else { ## If theta_true not provided, use posterior mean as proxy for (e in 1:n_edges) { k &lt;- Z_true[e] lambda_est[e, ] &lt;- lambda_mean[k, ] } lambda_true &lt;- lambda_est warning(&quot;theta_true not provided. Using posterior mean for comparison.&quot;) } ## Compare for a few representative edges edge_sample &lt;- sample(1:n_edges, min(6, n_edges)) comparison_data &lt;- data.frame( edge = rep(edge_sample, each = TT * 2), time = rep(1:TT, length(edge_sample) * 2), type = rep(c(&quot;True&quot;, &quot;Estimated&quot;), each = TT * length(edge_sample)), count = c( as.vector(lambda_true[edge_sample, ]), as.vector(lambda_est[edge_sample, ]) ) ) ggplot(comparison_data, aes(x = time, y = count, color = type)) + geom_line(linewidth = 0.8) + facet_wrap(~ edge, ncol = 3, labeller = labeller(edge = function(x) paste(&quot;Edge&quot;, x))) + scale_color_manual( name = &quot;&quot;, values = c(&quot;True&quot; = &quot;#2C7BB6&quot;, &quot;Estimated&quot; = &quot;#D7191C&quot;), labels = c(&quot;True Intensity&quot;, &quot;Posterior Mean&quot;) ) + labs( title = &quot;Intensity Estimation: True vs Posterior Mean&quot;, x = &quot;Time Step&quot;, y = &quot;Intensity (λ)&quot; ) + theme_minimal() + theme( legend.position = &quot;bottom&quot;, panel.grid.minor = element_blank(), strip.text = element_text(size = 9) ) } ## In your simulation script, after running MCMC: p_intensity &lt;- plot_intensity_estimation( mcmc_result, Y, Fmat, Z_true, K_true, theta_true = theta_true ## Pass the true parameters from data generation ) p_intensity 6.6 6. Combined Visualization ## Combine all diagnostic plots (p_network | p_timeseries) / (p_trace) / (p_convergence | p_recovery) / (p_posterior | p_heatmap) + plot_layout(guides = &quot;collect&quot;) &amp; theme(legend.position = &quot;bottom&quot;) 6.7 7. Summary Statistics ## Print summary summary(mcmc_result) ## Key metrics burn &lt;- mcmc_result$settings$burn keep_idx &lt;- seq(burn + 1, mcmc_result$settings$n_iter) cat(&quot;
